func solve(s string) int64 {
	n := len(s)
	if n == 0 {
		return 0
	}

	count0 := 0
	count1 := 0
	for _, char := range s {
		if char == '0' {
			count0++
		} else {
			count1++
		}
	}

	// Case 1: No swap
	// Find the longest balanced subarray in the original string s
	maxLenNoSwap := findLongestBalancedSubarray(s)

	// Case 2: One swap
	// The maximum length of a balanced subarray after one swap.
	// A balanced subarray must have an equal number of '0's and '1's.
	// If the total number of '0's and '1's are very different, one swap might not help much.

	// Let C0 and C1 be the total counts.
	// After one swap, the total counts C0 and C1 remain the same.
	// The longest possible balanced subarray length is 2 * min(C0, C1).

	maxLenAfterSwap := int64(0)

	// Iterate over all possible pairs of indices (i, j) where i < j
	// Swap s[i] and s[j]
	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			// Create the swapped string s_prime
			s_prime_bytes := []byte(s)
			s_prime_bytes[i], s_prime_bytes[j] = s_prime_bytes[j], s_prime_bytes[i]
			s_prime := string(s_prime_bytes)

			// Find the longest balanced subarray in s_prime
			currentMaxLen := findLongestBalancedSubarray(s_prime)
			if int64(currentMaxLen) > maxLenAfterSwap {
				maxLenAfterSwap = int64(currentMaxLen)
			}
		}
	}

	// The overall maximum is the max of Case 1 and Case 2.
	result := maxLenNoSwap
	if maxLenAfterSwap > result {
		result = maxLenAfterSwap
	}

	return result
}

// findLongestBalancedSubarray finds the length of the longest balanced (equal 0s and 1s) subarray in string t.
func findLongestBalancedSubarray(t string) int {
	n := len(t)
	if n == 0 {
		return 0
	}

	// Use prefix sums (balance: +1 for '1', -1 for '0')
	// A subarray t[i:j+1] is balanced if its sum is 0, i.e., prefix_sum[j+1] - prefix_sum[i] = 0
	// which means prefix_sum[j+1] = prefix_sum[i].

	// map stores: balance_value -> first_index_where_this_balance_was_achieved
	// Initialize with balance 0 achieved before the string starts (at index -1 conceptually)
	balanceMap := make(map[int]int)
	balanceMap[0] = -1 // Balance 0 occurs before index 0

	currentBalance := 0
	maxLength := 0

	for i := 0; i < n; i++ {
		if t[i] == '1' {
			currentBalance++
		} else { // t[i] == '0'
			currentBalance--
		}

		if firstIndex, ok := balanceMap[currentBalance]; ok {
			// We found a subarray t[firstIndex+1 : i+1] with balance 0
			length := i - firstIndex
			if length > maxLength {
				maxLength = length
			}
		} else {
			// First time seeing this balance, record the index
			balanceMap[currentBalance] = i
		}
	}

	return maxLength
}
