	// We want to maximize the length of a balanced substring.

	// Case 0: No swap.
	// We find the maximum length of a balanced substring in the original string s.
	maxLength := func(s string) int64 {
		n := len(s)
		if n == 0 {
			return 0
		}
		// Use prefix sums (balance array) for finding max length subarray with sum 0.
		// Let '0' -> -1, '1' -> 1. We want a subarray sum of 0.
		balance := make(map[int]int)
		balance[0] = -1 // Map sum to the *smallest* index where this sum occurred (or -1 for sum 0 before start)
		currentSum := 0
		maxLen := 0

		for i := 0; i < n; i++ {
			if s[i] == '1' {
				currentSum++
			} else {
				currentSum--
			}

			if prevIndex, found := balance[currentSum]; found {
				// Substring from prevIndex+1 to i is balanced. Length is i - prevIndex.
				maxLen = int(math.Max(float64(maxLen), float64(i-prevIndex)))
			} else {
				// Store the current index i+1 (which is the length of the prefix ending here)
				// Wait, we need the starting index. Let's store the index i.
				// If sum occurs at index j, and again at index i, the subarray s[j+1...i] sums to 0.
				balance[currentSum] = i
			}
		}
		return int64(maxLen)
	}(s)

	// Case 1: One swap.
	// Since N is up to 10^5, O(N^2) swaps * O(N) check is too slow.
	// We need a more efficient approach.

	// The maximum balanced substring length is 2 * min(C0_sub, C1_sub) where C0_sub = C1_sub.
	// The maximum possible length is 2 * min(total_count0, total_count1).
	// Let K = min(total_count0, total_count1). The answer is at most 2K.

	// If we can achieve a balanced substring of length L, it must contain L/2 zeros and L/2 ones.
	// The crucial insight is that a single swap can, at best, change the count of one specific character
	// within the *target* substring by 1.

	// Consider the maximum possible length: 2 * min(count0, count1).
	// If count0 == count1, the whole string is potentially balanced if we can arrange it.
	// If count0 != count1, say count0 < count1, the max possible balanced substring length is 2*count0.
	// Can we always achieve 2*count0 if we can swap to make the counts equal within the whole string?
	// No, because we are limited to a SUBSTRING.

	// If we swap s[i] and s[j] (where s[i] != s[j]), the characters at i and j change their value in the context of the substring.

	// The problem is equivalent to: find the maximum length L such that there exists a substring s' of length L
	// and a swap (i, j) resulting in S' where s' is balanced in S'.

	// Let's focus on the required count: we need L/2 zeros and L/2 ones.

	// The maximum possible length is limited by 2 * min(count0, count1). Let M = 2 * min(count0, count1).
	// We check if length L is achievable, starting from L=M down to 0.

	// Check function: can we achieve a balanced substring of length L?
	check := func(L int) bool {
		if L == 0 {
			return true
		}
		if L%2 != 0 {
			return false
		}
		targetCount := L / 2

		// Iterate over all possible starting positions 'start' for the substring of length L
		for start := 0; start <= n-L; start++ {
			end := start + L - 1

			// Count '0's and '1's in the original substring s[start...end]
			current0 := 0
			current1 := 0
			for k := start; k <= end; k++ {
				if s[k] == '0' {
					current0++
				} else {
					current1++
				}
			}

			// We need to change the counts (current0, current1) to (targetCount, targetCount)
			// using at most one swap involving indices *within* the substring [start, end] or involving one index outside.

			// A swap involves two indices i and j.
			// Case A: Both i and j are inside [start, end].
			// If s[i]='0' and s[j]='1', swapping them keeps counts (current0, current1) unchanged.
			// If s[i]='0' and s[j]='0', swapping them keeps counts (current0, current1) unchanged.
			// If s[i]='1' and s[j]='1', swapping them keeps counts (current0, current1) unchanged.
			// A swap entirely within the substring never changes the counts of '0' and '1' within that substring!

			// Case B: One index i is inside [start, end], and j is outside.
			// Suppose s[i] = '0' and s[j] = '1' (j outside). Swap them.
			// The count of '0' in the substring decreases by 1 (at i), and increases by 1 (at j, which is outside, so it's irrelevant to the substring count).
			// Wait, the character at j moves to i, and s[i] moves to j.
			// If s[i]='0', s[j]='1'. Swap -> s'[i]='1', s'[j]='0'.
			// Substring s[start...end]:
			// 1. s[i] changes from '0' to '1'. Current0 -= 1, Current1 += 1.
			// 2. s[j] changes from '1' to '0'. Since j is outside, this doesn't affect the substring count.
			// Net change in substring counts: -1 zero, +1 one.

			// We need to move from (current0, current1) to (targetCount, targetCount).
			// Difference needed: (targetCount - current0) zeros, (targetCount - current1) ones.
			// Let diff0 = targetCount - current0, diff1 = targetCount - current1.
			// We need to change counts by (diff0, diff1).
			// Note that diff0 + diff1 = 2*targetCount - (current0 + current1) = L - L = 0. So diff1 = -diff0.

			// We need to change the count of '0' by diff0, and '1' by -diff0.
			// If diff0 > 0, we need to introduce diff0 more '0's into the substring. This requires swapping an external '0' into the substring at an original '1' spot, or an internal '1' into an external spot at a '0' spot (which is impossible for net gain of 0).
			// If diff0 > 0, we need to convert diff0 '1's to '0's within the substring, or bring in '0's from outside while moving '1's out.

			// The most powerful single swap is:
			// 1. Swap internal '0' (at i) with external '1' (at j): Substring changes by (-1 zero, +1 one).
			// 2. Swap internal '1' (at i) with external '0' (at j): Substring changes by (+1 zero, -1 one).

			// Let D = current0 - targetCount. We need to change the zero count by -D.
			// If D > 0 (too many zeros): We need to decrease zero count by D.
			//   We need D swaps of type 1: internal '0' <-> external '1'. This requires D internal '0's and D external '1's.
			// If D < 0 (too few zeros): We need to increase zero count by |D|.
			//   We need |D| swaps of type 2: internal '1' <-> external '0'. This requires |D| internal '1's and |D| external '0's.

			// Since we only get ONE swap, the magnitude of the required change |D| must be 0 or 1.
			// |D| = |current0 - targetCount| <= 1.

			if current0 == targetCount && current1 == targetCount {
				// Already balanced, 0 swaps needed.
				return true
			}

			// Check if one swap can balance it:
			// 1. Target: (T, T). Current: (C0, C1). We need C0 -> T, C1 -> T.
			// 2. If C0 = T+1, C1 = T-1 (Need to lose one '0', gain one '1').
			//    Achievable if there is an internal '0' (to lose) and an external '1' (to gain).
			if current0 == targetCount+1 && current1 == targetCount-1 {
				// Need one swap of type 1: internal '0' <-> external '1'.
				// Internal '0' exists since current0 > targetCount.
				// External '1' must exist if count1 < total_count1.
				// Since current1 = targetCount-1 and total_count1 >= 2*targetCount (if C0=T+1, C1=T-1, total=2T).
				// If total_count1 > targetCount, there might be an external '1'.
				// Total count of '1's: count1. Substring has current1. Outside has count1 - current1.
				// We need count1 - current1 >= 1.
				if count1-current1 >= 1 {
					return true
				}
			}

			// 3. If C0 = T-1, C1 = T+1 (Need to gain one '0', lose one '1').
			//    Achievable if there is an internal '1' (to lose) and an external '0' (to gain).
			if current0 == targetCount-1 && current1 == targetCount+1 {
				// Need one swap of type 2: internal '1' <-> external '0'.
				// Internal '1' exists since current1 > targetCount.
				// External '0' must exist if count0 - current0 >= 1.
				if count0-current0 >= 1 {
					return true
				}
			}
		}
		return false
	}

	// Binary search for the largest L
	low := 0
	high := 2 * int(math.Min(float64(count0), float64(count1)))
	ans := 0

	for low <= high {
		mid := low + (high-low)/2
		if check(mid) {
			ans = int64(mid)
			low = mid + 2 // Try for an even larger length
		} else {
			high = mid - 2
		}
	}

	return ans
}
